// Import necessary libraries
import android.os.Bundle;
import android.view.View;
import androidx.appcompat.app.AppCompatActivity;
import com.google.android.material.textfield.TextInputEditText;

public class MainActivity extends AppCompatActivity {

    // Variables to hold account balance and PIN
    private double balance = 1000.0;
    private String pin;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        // Initialize PIN text field for user input
        TextInputEditText pinEditText = findViewById(R.id.pin_text_field);
    }

    public void login(View view) {
        // Get the user-input PIN
        pin = ((TextInputEditText) findViewById(R.id.pin_text_field)).getText().toString();

        // Validate the PIN (in a real-world app, this should be more secure)
        if (pin.equals("1234")) {
            // If valid, proceed to transaction processing
            processTransaction();
        } else {
            System.out.println("Invalid PIN");
        }
    }

    private void processTransaction() {
        // Process the transaction by deducting amount from balance
        double amount = 500.0;
        balance -= amount;

        // Display updated account balance
        findViewById(R.id.balance_text_view).setText("Balance: " + String.valueOf(balance));
    }

    public void deposit(View view) {
        // Get the user-input deposit amount
        double amount = Double.parseDouble(((TextInputEditText) findViewById(R.id.deposit_amount_text_field)).getText().toString());

        // Update account balance
        balance += amount;

        // Display updated account balance
        findViewById(R.id.balance_text_view).setText("Balance: " + String.valueOf(balance));
    }

    public void withdraw(View view) {
        // Get the user-input withdrawal amount
        double amount = Double.parseDouble(((TextInputEditText) findViewById(R.id.withdraw_amount_text_field)).getText().toString());

        // Check if sufficient balance for withdrawal
        if (balance >= amount) {
            // If sufficient, deduct amount from balance and display updated balance
            balance -= amount;
            findViewById(R.id.balance_text_view).setText("Balance: " + String.valueOf(balance));
        } else {
            System.out.println("Insufficient balance");
        }
    }
}